"""
MKT Christ — Luke chapters 2–3 (88 missing verses; 2:11 and 2:32 already present)
Output: data/commentary/mkt-christ/luke.json
Run: python3 scripts/zc-christ-luke-2-3.py
"""
import json, pathlib

ROOT = pathlib.Path(__file__).parent.parent

def load_comm(source, book):
    p = ROOT / 'data' / 'commentary' / source / f'{book}.json'
    if p.exists():
        return json.loads(p.read_text())
    return {}

def save_comm(source, book, data):
    p = ROOT / 'data' / 'commentary' / source / f'{book}.json'
    p.parent.mkdir(parents=True, exist_ok=True)
    p.write_text(json.dumps(data, ensure_ascii=False, indent=None))
    print(f'  wrote {p.relative_to(ROOT)}')

def merge_comm(existing, new_data):
    # INTENT: Merge new verse entries without overwriting already-present keys — safe to re-run.
    # CHANGE? If commentary JSON structure changes from {ch:{v:html}}, update this traversal.
    # VERIFY: Re-running the script should produce identical output (no duplicate or overwritten entries).
    for ch, verses in new_data.items():
        if ch not in existing:
            existing[ch] = {}
        for v, html in verses.items():
            if v not in existing[ch]:
                existing[ch][v] = html

LUKE_CH2_3 = {
"2": {
"1": "<p>The decree of Caesar Augustus for a universal census sets the Incarnation within secular world history. But the emperor's decree serves a higher purpose: it moves Joseph and Mary to Bethlehem, fulfilling Micah 5:2 ('But you, O Bethlehem Ephrathah... from you shall come forth for me one who is to be ruler in Israel'). The greatest empire of the ancient world becomes an unwitting instrument of the divine plan to place the King of kings in David's city. Caesar orders, but God orchestrates.</p>",
"2": "<p>The Quirinius census detail anchors the birth in documented Roman administrative history. Whatever the precise historical resolution, Luke's intention is clear: the birth of the Son of God is a datable, locatable event in world history — not myth. Christ's coming is not removed from ordinary time but embedded in it, fulfilling Isaiah's promise that the virgin would bear a son 'in the days of Ahaz' (Isa 7:14) — a real historical moment, not an timeless ideal.</p>",
"3": "<p>All going 'each to his own town' to be registered sets in motion the geography of fulfillment. Joseph's journey to Bethlehem is not incidental: it is the mechanism by which the Davidic lineage (Joseph is of David's house and lineage, v.4) coincides with the Bethlehem birthplace. Christ is born where the Messiah must be born (Mic 5:2; Matt 2:5-6), through the providential ordering of pagan empire. The census is Rome's tool; the birth-location is God's design.</p>",
"4": "<p>Joseph going 'because he was of the house and lineage of David' establishes the Davidic credentials of Jesus that ground the Messianic claim. Luke's genealogy (3:23-38) and this verse together confirm the Davidic descent through Joseph (legal father). The Davidic covenant (2 Sam 7:12-16 — 'I will raise up your offspring after you... I will establish his kingdom forever') finds its ultimate fulfillment not in Solomon or any subsequent king but in Jesus, the one whose kingdom has no end (Luke 1:32-33).</p>",
"5": "<p>Mary goes with Joseph to Bethlehem 'being with child' — the one who carries the eternal Son in her womb travels to the city of David. The Ark of the Covenant (which once carried the presence of God) was also brought to Jerusalem under David (2 Sam 6:12-15); now the true bearer of God's presence makes the same Davidic journey. Mary is the living ark, carrying the one who is greater than the temple (Luke 11:31) — the presence of God in human form.</p>",
"6": "<p>'While they were there, the time came for her to give birth' — the Incarnation comes to its culmination not in a royal palace but in the humility of an overcrowded village. This is the moment the eternal Son of God enters the full condition of human birth. Isaiah 9:6 announces: 'For to us a child is born, to us a son is given.' Luke's narrative is the fulfillment-moment of that announcement — the child who is born is also the Son who is given from eternity.</p>",
"7": "<p>'She gave birth to her firstborn son and wrapped him in swaddling cloths and laid him in a manger, because there was no room for them in the katalyma.' The manger — a feeding trough for animals — is the first throne of the Lord of creation. He who feeds all things (Ps 104:27-28) lies in a feeding trough, foreshadowing that he will give his flesh as food for the world (John 6:51). There was 'no room' for the one who is the room/dwelling-place of God (John 14:2); he who is the Bread of Life is laid where bread (grain) is eaten. Every detail of the nativity is theologically laden.</p>",
"8": "<p>Shepherds keeping watch in the fields are the first human witnesses of the Incarnation. David was called from keeping sheep (1 Sam 16:11-13; Ps 78:70-71) to be shepherd-king. Christ, the Son of David, is announced first to shepherds — pointing to himself as the Good Shepherd (John 10:11) who lays down his life for the sheep. Those socially marginal and ritually suspect (shepherds could not keep Sabbath or give testimony) are chosen as the first evangelists of the new David's birth.</p>",
"9": "<p>The angel of the Lord and the glory of the Lord shining around the shepherds echoes the theophany patterns of the OT: the divine glory (kabod YHWH) that filled the tabernacle (Exod 40:34-38) and the temple (1 Kgs 8:10-11) now announces the birth of the one in whom the fullness of the deity dwells bodily (Col 2:9). The 'great fear' of the shepherds is the appropriate response to divine encounter — the same fear that fell on Israel at Sinai (Exod 20:18-19) and on the prophets before theophanies.</p>",
"10": "<p>'I bring you good news of great joy that will be for all the people' — the angelic euangelion (good news) is the primary announcement of the gospel. The 'all the people' (panti tō laō) initially refers to Israel (the covenant people), but the Gentile expansion is embedded in Simeon's song (v.32). Christ's birth is the good news that resolves every dimension of human need: guilt (through forgiveness), death (through resurrection), alienation (through reconciliation). The 'great joy' the angel announces is the joy of the kingdom's arrival in the person of the King.</p>",
"11": "<p>Already present.</p>",
"12": "<p>'And this will be a sign for you: you will find a baby wrapped in swaddling cloths and lying in a manger' — the sign (sēmeion) given to the shepherds is paradoxical: the Messiah is identifiable by his poverty, not his glory. In the OT, signs confirmed divine messages (Exod 3:12; Isa 7:14 — the sign of Immanuel). Here the sign is the humility of the Incarnation itself: the Creator in a feeding trough. This is the pattern of Christ's self-revelation throughout Luke — he is known by his lowliness, not by worldly markers of power.</p>",
"13": "<p>The heavenly host praising God marks the Incarnation as a cosmic event: angels who have served in the presence of God since before creation now sing at the moment God enters creation as a human baby. The angels' doxology (v.14) addresses both the divine and human dimensions of the event — glory to God (the divine source) and peace to humans (the human recipients). Christ's birth is the junction-point where heaven and earth meet in the person of the God-man.</p>",
"14": "<p>'Glory to God in the highest, and on earth peace among those with whom he is pleased' — the angelic doxology structures the entire redemptive program of Luke-Acts. 'Glory to God' points to the ultimate end (doxology, Eph 1:6,12,14); 'peace on earth' is the content of salvation (shalom — comprehensive well-being, reconciliation with God). Christ is 'our peace' (Eph 2:14) who breaks down the dividing wall; his birth is the peace-event the angels herald. The entry acclamation (19:38) echoes this birth-song, framing the passion as the peace-making act the birth announced.</p>",
"15": "<p>'Let us go over to Bethlehem and see this thing that has happened' — the shepherds' response is the model of faith-response to the gospel: immediate action toward the revealed Christ. 'This thing that has happened' (to rhēma touto to gegonos) uses rhēma — word/event — the spoken word that became event (John 1:14 — the Word became flesh). The shepherds go to see the incarnate Word, the word-become-event, the rhēma made visible in a manger.</p>",
"16": "<p>'And they went with haste and found Mary and Joseph, and the baby lying in a manger' — the finding of Jesus in the manger completes the sign (v.12). The search for and finding of Christ is a pattern throughout Luke: the lost sheep, the lost coin, the lost son — all found with joy. The shepherds are the first seekers-and-finders of Christ, and their finding produces the joy the angel promised (v.10). The manger-scene as found matches exactly the sign given — the reliability of the divine word is confirmed.</p>",
"17": "<p>'And when they saw it, they made known the saying that had been told them concerning this child' — the shepherds become the first evangelists: recipients of the gospel who immediately proclaim it to others. The chain of proclamation that will structure Luke-Acts begins here: the angel proclaims to the shepherds, who proclaim to all around. Christ's birth generates its own witness — those who encounter him cannot but speak of him (Acts 4:20 — 'we cannot but speak of what we have seen and heard').</p>",
"18": "<p>'And all who heard it wondered at what the shepherds told them' — the wonder (thaumazō) of those who heard the shepherds' report is the universal first response to the gospel. Throughout Luke, wonder marks the encounter with divine action that exceeds comprehension. The shepherds' witness produces wonder — the appropriate posture before the mystery of the Incarnation — in all who hear. This wonder is not yet faith, but it is the opening of the door through which faith can come.</p>",
"19": "<p>'But Mary treasured up all these things, pondering them in her heart' — Mary's interior response (suntēreō — to keep carefully together; symbalousa — to throw together, reflect, compare) reflects the posture of one who receives revelation that exceeds immediate comprehension. This is the response of the faithful hearer to the mystery of Christ: not to dismiss what is not yet understood, but to hold it, keep it, allow it to unfold. Mary's pondering mirrors the reader's own engagement with the inexhaustible mystery of the Incarnation.</p>",
"20": "<p>'And the shepherds returned, glorifying and praising God for all they had heard and seen' — the witnesses' return with doxology completes the scene's liturgical arc: divine announcement → human seeking → divine confirmation → human praise. The phrase 'as it had been told them' (kathōs elalēthē pros autous) confirms that what they found matched what they were promised — the divine word is reliable. Their praise of God is the proper response to God's self-revelation in Christ: worship is the end-point of encountering the Incarnate Son.</p>",
"21": "<p>'And at the end of eight days, when he was circumcised, he was called Jesus' — the circumcision on the eighth day fulfills the covenant sign given to Abraham (Gen 17:12). Christ submits to the covenant obligation of circumcision — the sign of the Abrahamic covenant — though he is himself the one through whom the covenant's promises are fulfilled (Gal 3:16). His name 'Jesus' (YHWH saves, given by the angel, 1:31) identifies his mission: he is circumcised into the covenant whose deepest requirement — perfect obedience and substitutionary death — he will fulfill in his own body.</p>",
"22": "<p>'And when the time came for their purification according to the Law of Moses, they brought him up to Jerusalem to present him to the Lord' — Jesus's presentation in the temple fulfills the Torah's firstborn-redemption law (Exod 13:2, 12). The one who is himself the redemption of Israel (1:68) submits to the rite of being 'redeemed' by the substitutionary offering. He is brought to the temple — his 'Father's house' (2:49) — for the first time, the one greater than the temple (11:31) entering the structure that was always pointing toward him.</p>",
"23": "<p>'Every male who first opens the womb shall be called holy to the Lord' — the firstborn consecration law (Exod 13:2) that applies to Jesus is fulfilled not merely in the rite of presentation but in the entirety of his life and death. Jesus is holy to the Lord in an absolute sense — not merely designated as holy by ritual, but inherently holy by nature. He is the Holy One of God (1:35; 4:34) whose presentation in the temple is the beginning of the self-offering that culminates at Calvary.</p>",
"24": "<p>The offering of 'a pair of turtledoves, or two young pigeons' — the poverty offering (Lev 12:8) rather than the lamb — reveals the economic status of the Holy Family and the pattern of the Incarnation. The Lamb of God (John 1:29) who takes away the sin of the world is presented in the temple accompanied by the offering of those too poor to bring a lamb. He who is himself the ultimate sacrificial Lamb begins his life in the poverty that will characterize his entire ministry (Luke 9:58 — nowhere to lay his head).</p>",
"25": "<p>Simeon, 'waiting for the consolation of Israel' (paraklēsis tou Israēl) and 'the Holy Spirit was upon him' — Simeon is the representative of faithful Israel awaiting the messianic fulfillment of Isaiah's promise of consolation (Isa 40:1 — 'Comfort, comfort my people'). The Spirit who anointed the Servant (Isa 61:1; Luke 4:18) rests on Simeon, enabling prophetic recognition. When Simeon holds the infant Jesus, the long wait of Israel is fulfilled — the Consolation himself is held in human arms.</p>",
"26": "<p>'It had been revealed to him by the Holy Spirit that he would not see death before he had seen the Lord's Christ' — the Spirit's promise to Simeon is fulfilled in this moment of encounter with the infant Christ. The Spirit who reveals the Christ (John 15:26 — 'the Spirit of truth... will bear witness about me') has prepared Simeon to recognize what no external sign could make obvious: that this poor infant in a poverty offering is the Lord's Anointed. Simeon's recognition by the Spirit models Spirit-enabled faith in the Christ whom the world does not recognize.</p>",
"27": "<p>Simeon comes 'in the Spirit' into the temple — the same Spirit who revealed Christ to him now guides him to the encounter. The meeting of Simeon and the infant Christ in the temple is a moment of divine orchestration: the faithful representative of the old covenant meets the fulfiller of the new in the very location that holds the tension between them. The Spirit brings together the promise (old covenant) and the fulfillment (new covenant) in the person of the infant Christ.</p>",
"28": "<p>'He took him up in his arms and blessed God' — Simeon holding the infant Jesus and blessing God is the posture of one who has received the fulfillment of his life's hope. The word 'took up in his arms' (edexato auto eis tas agkala autou) uses a verb of reception — the same verb-family as 'receiving the kingdom of God like a child' (18:17). Simeon models the reception of Christ: with open arms, gratitude, and worship. He has received the one who will bear all things (Col 1:17 — 'in him all things hold together').</p>",
"29": "<p>'Lord, now you are letting your servant depart in peace' — the Nunc Dimittis is Simeon's death-preparation prayer, made possible by seeing Christ. He can die in peace (en eirēnē — in the peace of shalom) because the one who is himself the peace between God and humanity (Eph 2:14) has arrived. The 'release' (apolyeis — you are letting go, releasing) uses the same word for the release/forgiveness of sins. Having seen Christ, Simeon is released from the burden of waiting — and death becomes not a defeat but a departure in peace.</p>",
"30": "<p>'For my eyes have seen your salvation' (to sōtērion sou) — Simeon does not say 'I have seen the Savior' but 'I have seen your salvation' — identifying the infant himself with the act of salvation. Jesus is not merely the agent of salvation but the embodiment of it (Acts 4:12 — 'there is salvation in no one else'). Simeon's eyes see what Isaiah promised: 'All flesh shall see the salvation of God' (Isa 40:5; Luke 3:6). The infant in his arms is the salvation of God made visible.</p>",
"31": "<p>'Which you have prepared in the presence of all peoples' — the salvation Simeon holds is not for Israel alone but prepared before/in the presence of (kata prosōpon) all peoples. The universal scope of Christ's salvation is announced at his first temple appearance — before his ministry begins, before the cross, God through Simeon's prophecy declares the salvation of all peoples. This prepares for the Gentile mission of Acts and the fulfillment of the Abrahamic promise: 'in you all families of the earth shall be blessed' (Gen 12:3).</p>",
"32": "<p>Already present.</p>",
"33": "<p>'And his father and his mother marveled at what was said about him' — Mary and Joseph marvel at Simeon's prophetic utterance. Despite the annunciations they have already received (chs 1-2), the expanding disclosure of their son's identity generates continued wonder. The mystery of who Christ is exceeds all previous revelation — even those who know him most intimately are being led deeper into the inexhaustible truth of his person. This wonder anticipates Mary's pondering (v.19) and the disciples' ongoing bewilderment before the Christ who exceeds their categories.</p>",
"34": "<p>'Behold, this child is appointed for the fall and rising of many in Israel, and for a sign that is opposed' — Simeon's oracle over the child is the first passion prediction in Luke. Christ is a dividing stone: he causes the 'fall' (ptōsin — stumbling, falling) of those who reject him (Isa 8:14-15 — 'he will become a stone of offense and a rock of stumbling') and the 'rising' (anastasin — resurrection) of those who receive him. He is a sign 'opposed' (antilegomenon — spoken against) — the same verb used of Paul's mission in Acts 28:22. Christ crucified is the sign that divides.</p>",
"35": "<p>'And a sword will pierce through your own soul also' — the sword that will pierce Mary's soul is the passion of her Son. The same imagery appears in Ezek 14:17 (God's sword going through the land) and Zech 13:7 ('Strike the shepherd, and the sheep will be scattered'). Mary's suffering at the cross (John 19:25-27) fulfills this oracle: she will witness the death of the one she has borne, held, nursed, and raised. Christ's passion is not only his suffering but reaches those closest to him — he is not a private savior but one whose redemptive suffering cuts through to those who love him.</p>",
"36": "<p>Anna the prophetess, 'of the tribe of Asher,' appears after Simeon as a second witness (Deut 19:15 — two witnesses confirm). A prophetess receiving the infant Christ echoes the women prophets of Israel (Miriam, Deborah, Huldah) who stood at turning points of sacred history. Anna represents the remnant of faithful Israel who have been waiting through the long silence for the consolation (cf. the 400 years of prophetic silence). Her immediate recognition of the child signals that those attuned to the Spirit recognize Christ even when the world does not.</p>",
"37": "<p>'She did not depart from the temple, worshiping with fasting and prayer night and day' — Anna's life of unceasing temple prayer is the sustained posture of intercession for the consolation of Israel. She has made her whole life a waiting-in-prayer for Christ's arrival. Her eighty-four years of widowhood (or eighty-four years in the temple, depending on the Greek reading) represent the long patience of faithful expectation. When Christ arrives, she is there — those who persist in prayer before God are positioned to receive the answer when it comes.</p>",
"38": "<p>'And coming up at that very hour she began to give thanks to God and to speak of him to all who were waiting for the redemption of Jerusalem' — Anna becomes the first female evangelist: she proclaims the infant Christ to all who were waiting for redemption. 'The redemption of Jerusalem' (lytrōsin Ierousalēm) is the full covenantal restoration promised by the prophets (Isa 52:9 — 'the LORD has comforted his people, he has redeemed Jerusalem'). She announces that the one who will accomplish this redemption has arrived. Her witness is to the waiting community — those already oriented toward God's promises.</p>",
"39": "<p>'And when they had performed everything according to the Law of the Lord, they returned into Galilee, to their own town of Nazareth' — the Holy Family's faithful observance of Torah throughout the birth narrative (circumcision, purification, presentation) establishes Jesus's identity within Torah-obedient Israel. He comes not to abolish the law but to fulfill it (Matt 5:17). His return to Nazareth initiates the hidden years of growth — the period that prepares the public ministry. The King of kings is raised in an obscure Galilean village, the Word incarnate growing in wisdom as any human child.</p>",
"40": "<p>'And the child grew and became strong, filled with wisdom. And the grace of God was upon him' — Luke's summary of Jesus's development (mirroring 1 Sam 2:21,26 where Samuel 'grew and was in favor with the LORD and also with man') establishes the reality of the Incarnation: the eternal Son truly became human, truly grew, truly developed wisdom through normal human experience (Heb 5:8 — 'although he was a son, he learned obedience through what he suffered'). The grace of God upon him is not a supplement to his divine nature but the experiential dimension of his incarnate life.</p>",
"41": "<p>The annual Passover pilgrimage to Jerusalem grounds Jesus in the rhythm of Israel's covenant life. Passover commemorated the Exodus — the paradigmatic redemption event — with the lamb's blood protecting Israel from the destroying angel (Exod 12:1-28). Jesus participates annually in the feast that points to his own death as the true Passover Lamb (1 Cor 5:7 — 'Christ, our Passover lamb, has been sacrificed'). Each Passover Jesus keeps as a child is a participation in the type of which he is the antitype.</p>",
"42": "<p>At twelve years old — the threshold of religious majority in Judaism — Jesus makes the Passover pilgrimage and then stays behind. The age of accountability in Jewish tradition (approximately twelve for girls, thirteen for boys in later rabbinic tradition) is the moment when a child begins to take on Torah-responsibility personally. Jesus, at this threshold, demonstrates an identity and vocation that exceeds what his parents understand. His remaining in the temple is the first self-declaration of his unique relationship to the Father.</p>",
"43": "<p>'The boy Jesus stayed behind in Jerusalem. His parents did not know it' — the family's unawareness of Jesus's staying behind, and the three-day period before his finding (v.46), creates a narrative pattern that anticipates the passion: Jesus 'lost' for three days, sought with great distress, and found in the context of his Father's mission. The twelve-year-old's temple-remaining is a typological preview of the death and resurrection: three days of separation, then finding — 'he is not here... he is risen' (24:6).</p>",
"44": "<p>'Supposing him to be in the group they went a day's journey' — the parents' assumption that Jesus is 'in the group' reflects normal Passover caravan culture: large extended-family groups traveled together and a child could easily be assumed to be with relatives. The assumption fails here because Jesus is not where human expectation places him — he is in his Father's house. The pattern recurs throughout Luke: those who 'suppose' they know where Jesus is find he is elsewhere, pursuing the divine mission that exceeds human expectation.</p>",
"45": "<p>'And when they did not find him, they returned to Jerusalem, seeking him' — the return journey seeking the lost Jesus mirrors the three parables of Luke 15: the seeking of the lost sheep, the lost coin, the lost son. Mary and Joseph's anguished seeking of the 'lost' Jesus prefigures the seeking of all who lose sight of Christ and must return, seek, and find him where he truly is — in the things of his Father. The seeking of Christ is always the movement back toward the Father.</p>",
"46": "<p>'After three days they found him in the temple, sitting among the teachers, listening to them and asking them questions' — found in the temple after three days, Jesus is already engaged in the activity of his public ministry: teaching, questioning, revealing wisdom about the things of God. The three days and the temple-finding pattern the resurrection: after three days, Christ is found not where the disciples looked but where his Father's mission placed him. The twelve-year-old temple episode is Luke's first resurrection-type: lost, mourned, found alive and active.</p>",
"47": "<p>'And all who heard him were amazed at his understanding and his answers' — the same amazement (existanto) that will greet Jesus's teaching throughout his ministry (4:32; 9:43; 11:14; 20:26) begins here. The teachers in the temple — trained scholars of Torah — are astonished by the twelve-year-old's understanding. He who is himself the Wisdom of God (1 Cor 1:24; 1:30) sits in the temple absorbing and questioning, demonstrating that wisdom is not merely information but a mode of being in relation to God that Christ uniquely embodies.</p>",
"48": "<p>'Son, why have you treated us so? Behold, your father and I have been searching for you in great distress' — Mary's address 'your father and I' (ho patēr sou kagō) introduces the tension that Jesus's answer will resolve: Joseph is his father in one sense; God is his Father in the absolute sense. The distress (odynomenoi — in pain, suffering) of Mary and Joseph mirrors the distress of those who lose sight of Christ. Their pain is genuine and the anxiety of those who love Jesus and cannot find him is a real human experience, but Jesus's answer reorients the entire frame.</p>",
"49": "<p>'Why were you looking for me? Did you not know that I must be in my Father's house?' — the first words of Jesus in Luke's Gospel are a double rhetorical question that defines his identity and mission. 'I must' (dei) is the divine necessity that governs the entire Lukan narrative — Jesus must be in his Father's house, must proclaim the kingdom, must suffer, must be raised. His primary location is always with the Father; his primary identity is always the Son. The question is not a rebuke but a revelation: this is who I am. Remember this when you see what comes.</p>",
"50": "<p>'And they did not understand the saying that he spoke to them' — Mary and Joseph's non-understanding does not reflect ignorance about Jesus's identity (they know what the angels said) but the inexhaustibility of who he is. Each new disclosure of his identity exceeds previous comprehension. This non-understanding is the appropriate posture before the mystery of Christ: what has been revealed is real and true, but always more exceeds understanding. The disciples will repeatedly not understand (9:45; 18:34) until the Spirit opens their minds (24:45).</p>",
"51": "<p>'And he went down with them and came to Nazareth and was submissive to them' — the eternal Son who must be in his Father's house returns to Nazareth and submits to his human parents. This is the kenosis (self-emptying) in its most domestic form: the one by whom all things were made (John 1:3) grows up under Joseph's carpentry instruction; the Lord of the Sabbath submits to human parenting. 'He learned obedience through what he suffered' (Heb 5:8) — the submission at Nazareth is part of the obedience that qualifies him as our high priest and saves us.</p>",
"52": "<p>'And Jesus increased in wisdom and in stature and in favor with God and man' — the summary mirrors 1 Sam 2:26 (Samuel) and exactly matches the pattern of one who is genuinely human and growing. The Incarnation involved a genuine taking on of human development: wisdom increases, stature grows, social standing develops. The fully divine Son is also fully human — and his full humanity includes the humble process of human maturation that makes him 'able to sympathize with our weaknesses' (Heb 4:15), having been tempted in every way as we are.</p>"
},
"3": {
"1": "<p>Luke's sixfold historical dating (Tiberius, Pilate, Herod, Philip, Lysanias, Annas and Caiaphas) establishes John's ministry — and therefore the beginning of Christ's public work — in datable world history. Christ's mission enters real time, ruled by real powers. The contrast between these rulers and the one whose kingdom they cannot contain is the implicit theological point of Luke's Thucydidean synchronism.</p>",
"2": "<p>'The word of God came to John the son of Zechariah in the wilderness' — John receives the prophetic word (rhēma theou) in the wilderness, echoing the pattern of the OT prophets who received the word in the wilderness (Elijah in 1 Kgs 19; Moses in Exod 3). John is the last prophet of the old order, whose entire ministry is defined by pointing toward Christ. He receives the word in order to proclaim the Word who is coming (John 1:23) — his ministry is derivative, preparatory, and self-transcending.</p>",
"3": "<p>'He went into all the region around the Jordan, proclaiming a baptism of repentance for the forgiveness of sins' — John's baptism of repentance is the immediate preparation for Christ's baptism of Spirit and fire (v.16). The forgiveness of sins that John's baptism anticipates is accomplished by Christ's death (22:20 — 'poured out for you,' 24:47 — 'forgiveness of sins should be proclaimed in his name'). John creates the expectation; Christ fulfills it. Every baptism John performs points forward to the one who will baptize with the Holy Spirit.</p>",
"4": "<p>The citation of Isaiah 40:3-5 ('The voice of one crying in the wilderness: Prepare the way of the Lord, make his paths straight') identifies John's ministry as the Elijah-herald of Isaiah's prophecy. 'The Lord' (kyrios) whose way is being prepared is YHWH himself in Isaiah — applied here to Jesus, Luke equates Jesus with YHWH. John's wilderness proclamation is the highway-preparation for the arrival of the God of Israel in human form. The voice (John) exists entirely for the sake of the Word (Jesus).</p>",
"5": "<p>'Every valley shall be filled, and every mountain and hill shall be made low' — Isaiah's leveling of the terrain is the prophetic image for the radical social reversal that accompanies the divine visitation. Luke applies it to John's ministry of preparation: the social barriers that prevent access to God (valleys of marginalization, mountains of pride) will be removed by the gospel. Christ's ministry will enact this reversal: the poor exalted, the proud scattered (1:51-52). The terrain-leveling is the ethics of the kingdom made spatial.</p>",
"6": "<p>'And all flesh shall see the salvation of God' — Isaiah 40:5's climax becomes the stated program of Luke-Acts: salvation for all flesh (pasa sarx), not Israel alone. Christ is not the national Messiah of Israel only but the universal Savior who breaks every ethnic and social boundary. This verse prepares for the Gentile mission of Acts, the Ethiopian eunuch (Acts 8), Cornelius (Acts 10), and Paul's mission to the nations. The Incarnation is the event through which God's salvation becomes visible to all flesh.</p>",
"7": "<p>'You brood of vipers! Who warned you to flee from the wrath to come?' — John's address to the crowds who come to be baptized echoes the serpent-imagery of the Fall (Gen 3:1) and the prophetic indictments of Isaiah (14:29; 59:5) and Jeremiah (8:17). The 'wrath to come' (tēn mellousan orgēn) is the eschatological judgment that Christ's coming both announces and makes survivable through repentance and faith. John's harsh opening acknowledges that baptism without genuine repentance is empty ritual — the sacrament without the reality it signifies.</p>",
"8": "<p>'Bear fruits in keeping with repentance' — genuine repentance is not merely emotional remorse but the transformation of life that corresponds to a changed heart (metanoia — change of mind/orientation). The warning 'do not begin to say to yourselves, We have Abraham as our father' targets the assumption that ethnic covenant membership substitutes for personal repentance. Christ himself will embody the perfect fruit of the Spirit — the one whose repentance (metanoia) is on behalf of those who cannot repent sufficiently. His righteousness covers our failure to bear adequate fruit.</p>",
"9": "<p>'Even now the axe is laid to the root of the trees' — the imminence of judgment ('even now,' ēdē) establishes the eschatological urgency of John's preaching. The axe at the root is not cutting branches but the tree itself — total judgment, not trimming. Christ comes as the agent of this final judgment (Luke 3:17 — his winnowing fork is in his hand). But he also comes as the one who absorbs the judgment himself: the axe that should fall on the trees falls instead on the Lamb of God who takes away the world's sin.</p>",
"10": "<p>'What then shall we do?' — the crowds' question in response to John's preaching is the fundamental question before the gospel proclamation. The same question will be asked at Pentecost (Acts 2:37). John's answer (sharing, justice, non-exploitation) describes the ethical fruits of repentance. Christ will later describe the same ethical transformation in terms of the kingdom: those who have received the King share his generosity, his justice, and his refusal to exploit. The 'doing' of repentance flows from the receiving of Christ.</p>",
"11": "<p>'Whoever has two tunics is to share with him who has none, and whoever has food is to do likewise' — the sharing of basic necessities (tunics, food) as the concrete expression of repentance anticipates Christ's own teaching in the Sermon on the Plain (6:30-31) and the parable of the Rich Fool (12:16-21). Christ himself embodies this principle absolutely: he has nowhere to lay his head (9:58) and gives everything he has — including his life — for those who have nothing.</p>",
"12": "<p>Tax collectors coming to John's baptism is a social boundary-crossing moment — tax collectors were ritually impure and socially despised. Their reception of baptism is the first instance of the gospel reaching those whom the religious establishment had categorized as beyond the covenant. John does not turn them away, prefiguring Jesus's own practice of eating with tax collectors (5:29-32; 15:1-2; 19:1-10). The redemption John prepares is the redemption Christ will enact — one that refuses to respect the boundary-markers of religious respectability.</p>",
"13": "<p>'Collect no more than you are authorized to do' — John's practical ethic for tax collectors is not to leave their profession but to practice it with justice. The occupational redemption John calls for anticipates what Christ achieves in Zacchaeus (19:8 — voluntary fourfold restoration). John's ethical instruction prepares the ground; Christ's transformative presence produces the fruit. The progression from John's instruction to Jesus's transformative encounter shows the difference between law-preparation and gospel-fulfillment.</p>",
"14": "<p>Soldiers asking 'what shall we do?' receive practical instruction: 'do not extort money from anyone by threats or by false accusation, and be content with your wages.' Christ himself will commend a Roman centurion's faith as the greatest in Israel (7:9) — the occupational vocation is not condemned but reformed. This foreshadows the inclusion of Gentile soldiers (Cornelius, Acts 10) in the community of Christ. John's instruction to soldiers is preparation for Christ's universal redemption that crosses military and ethnic lines.</p>",
"15": "<p>'As the people were in expectation, and all were questioning in their hearts concerning John, whether he might be the Christ' — the messianic expectation that surrounds John positions the question of identity that will define the entire Gospel: who is the Christ? John's denial of being the Christ (v.16) clears the field for Jesus — but the expectation he generates will only be satisfied by Christ himself. John's ministry creates the longing that only Christ can fill. He is the arouser of expectation, not its fulfillment.</p>",
"16": "<p>'I baptize you with water, but he who is mightier than I is coming, the strap of whose sandals I am not worthy to untie. He will baptize you with the Holy Spirit and fire' — John's self-diminishment before Christ is the posture of all true ministry: 'He must increase, but I must decrease' (John 3:30). The Spirit-baptism he announces (Isa 44:3; Joel 2:28-29) is fulfilled at Pentecost (Acts 2:1-4) and constitutes the distinctive mark of the new covenant community. Christ does not merely improve on John's ministry; he inaugurates an entirely new order of divine presence.</p>",
"17": "<p>'His winnowing fork is in his hand, to clear his threshing floor and to gather the wheat into his barn, but the chaff he will burn with unquenchable fire' — the harvest metaphor positions Christ as the eschatological judge who separates the genuine from the counterfeit, the repentant from the unrepentant. The same Christ who comes with the Spirit-baptism of grace comes also with the fire-judgment of holiness. Salvation and judgment are not two different Christs but two aspects of the one Christ's coming — grace to those who receive him, judgment to those who reject him.</p>",
"18": "<p>'So with many other exhortations he preached good news to the people' — Luke summarizes John's ministry as 'preaching good news' (euēngelizeto), the same verb used for Jesus's gospel proclamation. John's preparatory ministry is itself a form of gospel preaching — the herald's announcement partakes of the nature of the one it announces. The genre of his ministry is defined by its content: the coming of Christ makes even the announcement of his arrival a gospel event.</p>",
"19": "<p>Herod Antipas's imprisonment of John for his rebuke over Herodias begins the pattern that will end in John's death (recorded in 9:7-9) and anticipates Christ's own passion. The righteous herald is silenced by the king who cannot tolerate prophetic truth-speaking. Christ himself will stand before Herod Antipas (23:6-12), treated with contempt, and sent to crucifixion. John's fate is the type of which Christ's passion is the antitype — though Christ's death is not martyrdom but redemption.</p>",
"20": "<p>'Added this to them all, that he locked up John in prison' — the imprisonment that silences John is the darkness before Christ's light blazes into full visibility. John's 'exit' from the narrative (his imprisonment, not his death, is Luke's transition point) coincides with Jesus's emergence into public ministry. The forerunner has served his purpose; now the one he announced steps forward. The pattern is deliberate: John must decrease so that Christ may increase fully in Luke's narrative.</p>",
"21": "<p>'Now when all the people were baptized, and when Jesus also had been baptized and was praying, the heavens were opened' — Jesus's baptism by John is the self-identification of the sinless one with sinners. He who had no sin (2 Cor 5:21) submits to a baptism of repentance for the forgiveness of sins — taking his place among those he came to redeem. The heavens opening at his baptism reverses the post-Eden barrier between heaven and earth (Gen 3:24 — the cherubim barring access). In Christ, the access to God is restored.</p>",
"22": "<p>'The Holy Spirit descended on him in bodily form, like a dove; and a voice came from heaven, You are my beloved Son; with you I am well pleased' — the Trinitarian disclosure at the baptism (Son baptized, Spirit descending, Father speaking) is the most explicit pre-resurrection revelation of the Trinity in Luke. The Father's voice quotes Psalm 2:7 ('You are my Son') and Isaiah 42:1 ('my chosen, in whom my soul delights'). The Davidic Son and the Servant are identified as the same person — Jesus will reign as the Davidic King through the Servant's path of suffering and obedience.</p>",
"23": "<p>'Jesus, when he began his ministry, was about thirty years of age, being the son (as was supposed) of Joseph, the son of Heli' — the genealogy begins with the disclaimer 'as was supposed' (hōs enomizeto) — Jesus is not actually the biological son of Joseph but is legally so. The genealogy traces Christ's lineage through Mary (on most readings of Luke's vs. Matthew's Josephic genealogy) or through Joseph's legal line to establish the legal Davidic claim. His public ministry begins where the great Jewish leaders typically began: the age of thirty (Num 4:3, 47; 2 Sam 5:4 — David became king at thirty).</p>",
"24": "<p>The genealogy through Matthat, Levi, Melchi, Jannai, Joseph traces the line of the legal heirs to the Davidic throne through the post-exilic period. Each name in the genealogy represents a link in the chain of covenant faithfulness through which God preserved the Davidic line against every historical pressure — Babylonian exile, Persian occupation, Hellenistic assimilation, Roman dominion — until the fullness of time arrived (Gal 4:4). The genealogy is a history of divine faithfulness preceding Christ.</p>",
"25": "<p>Through Mattathias, Amos, Nahum, Esli, Naggai — these post-exilic ancestors are otherwise unknown to history but known to God. The genealogy's inclusion of obscure names witnesses to divine covenant-memory: God does not forget a single link in the chain that leads to Christ. The obscurity of most of the genealogy's names reflects the hiddenness of God's providential work through history — the preservation of the messianic line through centuries of mundane, unrecorded lives.</p>",
"26": "<p>Through Maath, Mattathias, Semein, Josech, Joda — the continuity of the Davidic line through the exile and return required extraordinary providential preservation. The Babylonian captivity threatened to end the Davidic dynasty permanently; the Persian period offered survival without sovereignty. Yet God maintains the thread through generation after generation, each name a testimony to the divine commitment to fulfill the covenant with David (2 Sam 7:16 — 'your throne shall be established forever').</p>",
"27": "<p>Through Joanan, Rhesa, Zerubbabel, Shealtiel, Neri — Zerubbabel and Shealtiel are the most recognizable names in this portion of the genealogy (Ezra 3:2; Hag 1:1; Zech 4:6-10). Zerubbabel led the first return from Babylonian exile and laid the foundation of the second temple. As a descendant of both Solomon's line and through Neri, he represents the reconstitution of the Davidic line after the catastrophe of exile. Christ descends from the one who rebuilt the temple — and is himself the true Temple (John 2:19-21).</p>",
"28": "<p>Through Melchi, Addi, Cosam, Elmadam, Er — the post-exilic genealogy continues through otherwise unknown generations. The silence of Scripture about these individuals does not indicate their insignificance in the divine economy: they are the vessels through which the messianic line was carried. The genealogy itself is an act of witness to the value of every human life in the redemptive plan — no generation is skipped, no link unnecessary, each life a part of the chain leading to Christ.</p>",
"29": "<p>Through Joshua, Eliezer, Jorim, Matthat, Levi — the presence of Joshua (Iēsous in Greek — the same name as Jesus) in the genealogy creates a typological resonance. Joshua led Israel into the Promised Land; Jesus leads God's people into the eternal inheritance. The common name signals a common pattern: a successor who completes what Moses (the law) could not — bringing the people into rest (Heb 4:8-9). The name Joshua/Jesus recurs in Christ's lineage as a constant reminder of the type he fulfills.</p>",
"30": "<p>Through Simeon, Judah, Joseph, Jonam, Eliakim — the tribal ancestor Judah appears in the genealogy, situating Christ within the Judahite line that carried the scepter-promise (Gen 49:10 — 'the scepter shall not depart from Judah'). The lion of Judah (Rev 5:5) descends through a line that includes the tribal patriarch who pledged himself as surety for Benjamin (Gen 44:33) — an act of substitutionary self-offering that typologically prefigures Christ's substitutionary death.</p>",
"31": "<p>Through Melea, Menna, Mattatha, Nathan, David — the genealogy reaches David through Nathan (David's son, 2 Sam 5:14; 1 Chr 3:5), not through Solomon as Matthew's genealogy does. Luke's genealogy through Nathan gives the biological/Marian line while Matthew's through Solomon gives the royal/legal line through Joseph. Christ inherits both: the biological descent from David (through Mary-Nathan line) and the legal royal succession (through Joseph-Solomon line). He is David's son in every sense the covenant requires.</p>",
"32": "<p>Through Jesse, Obed, Boaz, Sala, Nahshon — the genealogy reaches back through Jesse (David's father, 1 Sam 16:1) to the ancestors of the Davidic line. Boaz and Ruth (Obed's parents) represent the Gentile inclusion in the Davidic line (Ruth was a Moabitess) — an anticipation of the universal scope of Christ's salvation that Luke emphasizes. Christ descends from a Gentile grandmother in the Davidic line, making the inclusion of Gentiles in his salvation consistent with his own ancestry.</p>",
"33": "<p>Through Amminadab, Admin, Arni, Hezron, Perez, Judah — Perez was born of Tamar's union with Judah (Gen 38) — a scandalous episode involving Judah's failure and Tamar's cunning that nevertheless produced an ancestor of Christ. The messianic line runs through moral failure and unexpected grace, not through pristine righteousness. This pattern (present also in Matthew's genealogy, which names Tamar, Rahab, Ruth, and Bathsheba) signals that Christ's redemption reaches into the depths of human moral disorder — he identifies with it in his very ancestry.</p>",
"34": "<p>Through Jacob, Isaac, Abraham — the genealogy reaches the patriarchs through whom the covenant promises were given. Abraham received the promise of blessing for all nations (Gen 12:3); Isaac was the child of promise (Gen 17:19; 21:12); Jacob became Israel, whose twelve sons form the foundation of the covenant people. Christ fulfills every covenant made with the patriarchs: the Abrahamic promise (all nations blessed in him, Gal 3:8,16), the Isaanic birth-of-promise pattern (born miraculously, the true child of promise, Gal 4:28-29), and the Jacobite-Israel pattern (the true Israel who succeeds where Jacob failed).</p>",
"35": "<p>Through Terah, Nahor, Serug, Reu, Peleg, Eber, Shelah — the genealogy moves into the post-flood, pre-Abrahamic generations. These are the ancestors through whom the human line was preserved from the flood to the call of Abraham. The genealogy in this section echoes Genesis 11's table of nations, positioning Christ within the universal human family. He comes not merely as the fulfillment of Israel's covenant but as the new humanity's representative head (1 Cor 15:45-49 — the last Adam).</p>",
"36": "<p>Through Cainan, Arphaxad, Shem, Noah — the genealogy reaches Noah, 'a herald of righteousness' (2 Pet 2:5), through whose obedience the human race was preserved from destruction. The flood and the ark prefigure baptism (1 Pet 3:20-21) — the salvation of the few through water, which itself points to Christ's death and resurrection. Noah was preserved to be a new Adam who would populate the post-flood world; Christ is the final Adam who redeems the world through his death and populates the new creation through his resurrection.</p>",
"37": "<p>Through Methuselah, Enoch, Jared, Mahalalel, Kenan, Enosh, Seth — the genealogy extends through the antediluvian patriarchs of Genesis 5. Enoch, who 'walked with God, and he was not, for God took him' (Gen 5:24), appears in this chain as a type of the one who was taken up into heaven without tasting death as mortals do — though Christ's ascension was through death and resurrection rather than the translation Enoch experienced. The pre-flood patriarchs' great longevity witnesses to humanity's original created dignity, now recaptured in Christ the new Adam.</p>",
"38": "<p>'The son of Enos, the son of Seth, the son of Adam, the son of God' — the genealogy ends where Luke's Gospel begins its root claim: Adam was the son of God (created in God's image and likeness, Gen 1:26-27). Christ, who is also the Son of God (1:35; 3:22), is the new Adam who restores what the first Adam lost. The genealogy traces Christ's humanity back to its divine origin: created in God's image, now fallen, now redeemed through the one who is both the last Adam and the eternal Son. The genealogy ends where the Gospel's deepest claim begins.</p>"
}
}

def main():
    existing = load_comm('mkt-christ', 'luke')
    merge_comm(existing, LUKE_CH2_3)
    save_comm('mkt-christ', 'luke', existing)
    ch2 = len(existing.get('2', {}))
    ch3 = len(existing.get('3', {}))
    print(f'Luke 2: {ch2}/52 verses. Luke 3: {ch3}/38 verses.')

if __name__ == '__main__':
    main()
